import React from "react";
import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import NavBar from "../home-page/components/navbar";
import Carousel from "../home-page/components/carousel";
import Footer from "../home-page/components/footer";
import UserProfile from "../profile/components/user-profile";
import Collection from '../Collection/components/CollectionBody';
import Author from '../Authority/components/AuthorBody';
import Login from '../Login/components/loginPage';
import "../../index.css";
import "bootstrap/dist/css/bootstrap.min.css";
import "bootstrap-icons/font/bootstrap-icons.css";

function HomePage() {
  return (
    <>
      <NavBar />
      <Carousel />
      <Footer />
    </>
  );
}

// Protected Route component
function ProtectedRoute({ children }) {
  const isLoggedIn = localStorage.getItem('isLoggedIn') === 'true';
  return isLoggedIn ? children : <Navigate to="/" />;
}

function App() {
  return (
    <BrowserRouter>
      <Routes>
        {/* Default route shows Login page */}
        <Route path="/" element={<Login />} />

        {/* Protected routes - only accessible after login */}
        <Route 
          path="/home" 
          element={
            <ProtectedRoute>
              <HomePage />
            </ProtectedRoute>
          } 
        />
        <Route
          path="/profile"
          element={
            <ProtectedRoute>
              <NavBar />
              <UserProfile />
              <Footer />
            </ProtectedRoute>
          }
        />
        <Route
          path="/collection"
          element={
            <ProtectedRoute>
              <NavBar />
              <Collection />
              <Footer />
            </ProtectedRoute>
          }
        />
        <Route
          path="/authority"
          element={
            <ProtectedRoute>
              <NavBar />
              <Author />
              <Footer />
            </ProtectedRoute>
          }
        />

        {/* Redirect all unknown routes to login */}
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
